What does this program print?

```cpp
#include <iostream>
struct Km {
    int val;
    Km(int v) : val{v} {}
};
void trip(Km k) { std::cout << k.val << "km\n"; }
int main() {
    trip(42);
    trip(Km{10});
}
```

