};
```

Which of the following compiles without error?

A student wants `Sensor` to reject implicit conversions. They add `explicit` but the code still compiles. What is the bug?

```cpp
#include <iostream>
struct Sensor {
    int id;
    explicit Sensor(int i, int channel = 0) : id{i} {}
};
void read(Sensor s) { std::cout << s.id << "\n"; }
int main() {
    read(7);  // student expects compile error
}
```

Why is it almost always wrong to mark a copy constructor `explicit`?

```cpp
struct Widget {
    explicit Widget(const Widget&) = default;
};
Widget a{};
Widget b = a; // What happens?
```

Does this program compile? If yes, what does it print?

```cpp
#include <iostream>
struct Flag {
    bool val;
    explicit Flag(bool b) : val{b} {}
};
void show(Flag f) { std::cout << (f.val ? "on" : "off") << "\n"; }
int main() {
    Flag f{true};
    show(f);
    show(Flag{false});
}
```
